VALUES
  ('social-worker-moex-01981', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '「食物銀行」提供實物（食物）給需要的家庭及民眾，以回應他們的生活需求。相對於現金給付，實物 （食物）給付有其優點與缺點；下列那一個選項的觀點並不正確？', '["實物（食物）給付的管理與運作，相較於現金給付，建置門檻通常較高", "相較於現金給付，實物（食物）給付的接受者選擇機會與空間受到限縮", "實物（食物）給付成本太高，應該以現金給付替代", "實物（食物）給付的過程難免會有一些耗損，耗損的成本應該被接受與計算"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01982', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', 'Gilbert及 Terrell認為社會福利政策的研究主要有三類，請問以下那個選項的組合是兩位學者的分類？', '["過程的研究", "產出的研究", "參與者的研究", "成效評估研究"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01983', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國對於育嬰留職停薪之受僱者，其有關育嬰留職停薪津貼之申請條件與發放，主要規定於以下那個法 規中？', '["性別工作平等法", "就業服務法", "就業保險法", "勞工保險條例"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01984', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列那一個類型的福利制度，主要根據個人的勞動參與年資、勞動市場的薪資與貢獻，來決定福利給付？', '["失業勞工的社會救助", "老年農民的福利津貼", "國民年金保險給付", "投保勞工保險的退休勞工"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01985', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列敘述中，那一個選項最不符合社會政策的定義與原則？', '["社會政策是關乎民眾福祉的生活情境之維持、創造、改變之指導原則與作為", "社會政策的制定，必須確保價值中立，以符合多數民眾的利益", "社會政策的制定過程，必須考量資源的調度與配置", "社會政策的實施，涉及福利服務輸送的抉擇與規劃"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01986', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '為防制兒童或少年遭受利用從事性交之對價行為，危害兒童身心之健全發展，下列那一個選項正確？', '["針對上述狀況，現行防制、規範及保護兒童少年的法規名稱是「兒童及少年性交易防制條例」", "根據現行法律規範，檢察官、司法警察官及司法警察查獲及救援被利用從事性交對價關係之兒童或少 年被害人後，應於48小時內將被害人交由當地直轄市、縣（市）主管機關處理", "直轄市、縣（市）主管機關經評估被害人須緊急安置，應於安置起72小時內，評估有無繼續安置之必 要；經評估有安置必要者，應提出報告，聲請法院裁定", "主管機關應於被害人安置後60日內，向法院提出審前報告，包括安置評估及處遇方式之建議，以作為 法院認定是否繼續安置之參考"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01987', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '當今臺灣社會生育率低，其原因多元。若政府想要鼓勵民眾生育，提升生育率，在下列四個選項中，那 一個選項是社會政策相較容易介入，並產生影響民眾願意生育的效果？', '["市場托育費用太高、品質參差不齊，影響民眾生育意願", "現代社會青年人的生活型態與婚姻觀轉變，延遲結婚的進程", "婦女教育程度提升，考量教育投資及個人發展而全力投入勞動市場", "民眾理性計算結婚與養育子女的成本影響到個人自主與生活品質，選擇不婚或不生"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01988', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國於2015年公布長期照顧服務法，並於2017年6月正式施行。在下列選項中，那一個選項與長期照 顧服務法之法令規定不合？', '["長期照顧服務之提供，不得因服務對象之國籍而有差別待遇", "根據該法第21條，長照機構依服務內容，區分為居家式服務類、社區式服務類、機構住宿式服務類、 綜合式服務類及政府公告類別等", "長期照顧主管機關在訂定長照服務品質基準時，應以區域資源配置為中心原則", "多元文化是長照服務資源調查、配置與服務規劃發展時必須考慮的要素"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01989', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '以「歷史制度論」探究社會政策的制訂與發展，下列那個不符合此論點的敘述？', '["「歷史脈絡」是社會政策與制度生成的特殊環境", "新政策與制度的建立往往必須激進的打破歷史陳疴，才能新瓶裝新酒", "政治、經濟、宗教、意識型態、社會環境等往往與社會政策的形成產生特殊互動，成為社會政策的分 析基礎", "社會政策的形成與發展，往往與先前政策之間形成「路徑依賴」關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01990', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列那一個選項的論述最不符合「社會投資」（social investment）的理念與作為？', '["「社會投資」的福利政策認為放任的自由經濟造成貧富差距日益擴大，強力主張政府扮演所得再分配 的角色", "社會投資策略強調機會的平等，主張政府應將社會支出用在人力資本的發展上", "政府提供彈性與安全的短期公共工作機會，協助職業災害青年探索工作機會與適應，協助重返職場， 是屬於社會投資的策略", "政府近年來針對女性單親或弱勢婦女所推動的微型創業方案，可說是屬於社會投資策略的運用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
